export enum SudokuActionType {
  // Restart game.
  RESTART = '@sudoku/restart',

  // Reset game.
  RESET = '@sudoku/reset',

  // Start game.
  START = '@sudoku/start',

  // Pause game.
  PAUSE = '@sudoku/pause',

  // Resume game.
  RESUME = '@sudoku/resume',

  // Game finished.
  FINISHED = '@sudoku/finished',

  // CHANGE the activated board cell.
  ACTIVE = '@sudoku/active',

  // Asking for a hint.
  HINT = '@sudoku/hint',

  // Requesting to view the cheat.
  TOGGLE_CHEAT_VISIBILITY = '@sudoku/toggle-cheat-visibility',

  // Input into a board cell.
  INPUT = '@sudoku/input',

  // Update the time spent in current game.
  REFRESH_TIME_USED = '@sudoku/refresh-time-used',
}

export enum SudokuInstructionType {
  ERASE = 'erase',
  HINT = 'hint',
  WRITE = 'write',
}
