import type { ISudokuBoard } from '@algorithm.ts/sudoku'
import type { ISudokuBoardCell } from '../context'

export const findCandidateHintCell = (
  SUDOKU_SIZE: number,
  attempt: Readonly<ISudokuBoard>,
  puzzle: Readonly<ISudokuBoard>,
  solution: Readonly<ISudokuBoard>,
): ISudokuBoardCell | null => {
  let r = 0
  let c = 0

  // Empty cell first.
  for (; r < SUDOKU_SIZE; ++r) {
    for (; c < SUDOKU_SIZE; ++c) {
      if (attempt[r][c] === -1) {
        return { r, c }
      }
    }
  }

  // Find a incorrect grid.
  for (; r < SUDOKU_SIZE; ++r) {
    for (; c < SUDOKU_SIZE; ++c) {
      if (puzzle[r][c] === -1 && attempt[r][c] !== solution[r][c]) {
        return { r, c }
      }
    }
  }

  return null
}
