import { css, cx } from '@emotion/css'
import PropTypes from 'prop-types'
import React from 'react'

export interface ISudokuBoardBorders {
  /**
   * Sudoku size, sqrt of the number of rows or columns.
   */
  SUDOKU_SIZE_SQRT: number
}

export const SudokuBoardBorders: React.FC<ISudokuBoardBorders> = ({ SUDOKU_SIZE_SQRT }) => {
  const classes = useStyles()
  return React.useMemo(() => {
    const SUDOKU_SIZE = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT
    const borders: React.ReactNode[] = []
    for (let i = SUDOKU_SIZE_SQRT, j = -1; i < SUDOKU_SIZE; i += SUDOKU_SIZE_SQRT, ++j) {
      const position = `calc(${i} * var(--kyokuya-sudoku__board-cell-size) + ${i + j}px)`
      borders.push(
        <div
          key={`h-${i}`}
          className={cx(classes.boarder, classes.horizontalBoarder)}
          style={{ top: position }}
        />,
      )
      borders.push(
        <div
          key={`v-${i}`}
          className={cx(classes.boarder, classes.verticalBorder)}
          style={{ left: position }}
        />,
      )
    }
    return <React.Fragment>{borders}</React.Fragment>
  }, [SUDOKU_SIZE_SQRT, classes])
}

SudokuBoardBorders.propTypes = {
  SUDOKU_SIZE_SQRT: PropTypes.number.isRequired,
}

const useStyles = () => {
  return React.useMemo(
    () => ({
      boarder: css`
        position: absolute;
        box-sizing: content-box;
        background: var(--kyokuya-sudoku__board-border-thickness-color);
      `,
      horizontalBoarder: css`
        left: 0;
        right: 0;
        bottom: unset;
        width: calc(100% + 2px);
        height: var(--kyokuya-sudoku__board-border-thickness);
      `,
      verticalBorder: css`
        top: 0;
        bottom: 0;
        right: unset;
        height: calc(100% + 2px);
        width: var(--kyokuya-sudoku__board-border-thickness);
      `,
    }),
    [],
  )
}
